import './AvatarGroup.scss';

import React, { useMemo } from 'react';

import { classNames } from '../../helpers/classnames';
import { Avatar } from '../Avatar';
import { Typography } from '../Typography';
import type { AvatarGroupProps } from './AvatarGroup.types';

export const AvatarGroup: React.FC<AvatarGroupProps> = ({
	size = 'medium',
	variant = 'circle',
	avatars,
	remainingCount,
	maxVisible = 7,
	onClick,
	className,
	dataTestId = 'AvatarGroup',
	...props
}) => {
	// Определяем видимые аватары (максимум maxVisible)
	const visibleAvatars = useMemo(() => {
		return avatars.slice(0, maxVisible);
	}, [avatars, maxVisible]);

	// Вычисляем remainingCount автоматически, если не задан явно
	const calculatedRemainingCount = useMemo(() => {
		if (remainingCount !== undefined) {
			return remainingCount;
		}
		const hiddenCount = avatars.length - maxVisible;
		return hiddenCount > 0 ? hiddenCount : undefined;
	}, [avatars.length, maxVisible, remainingCount]);

	// Определяем отступ для наложения в зависимости от размера
	const overlapOffset = size === 'medium' ? 8 : 4;

	return (
		<div
			{...props}
			data-testid={dataTestId}
			onClick={onClick}
			className={classNames(
				'dsb_avatar-group',
				`dsb_avatar-group--${size}`,
				onClick && 'dsb_avatar-group--clickable',
				className,
			)}
		>
			<div className="dsb_avatar-group__avatars">
				{visibleAvatars.map((avatarProps, index) => (
					<Avatar
						key={index}
						{...avatarProps}
						size={size}
						variant={variant}
						className={classNames(
							'dsb_avatar-group__avatar',
							index > 0 && 'dsb_avatar-group__avatar--overlap',
							avatarProps.className,
						)}
						style={{
							marginLeft: index > 0 ? `-${overlapOffset}px` : undefined,
							...avatarProps.style,
						}}
					/>
				))}
			</div>
			{calculatedRemainingCount !== undefined && calculatedRemainingCount > 0 && (
				<Typography variant="body3" inactive className="dsb_avatar-group__remaining-count">
					+{calculatedRemainingCount}
				</Typography>
			)}
		</div>
	);
};
